# commit/monitor.py
from dataclasses import dataclass
from datetime import date

@dataclass
class CommitUtilisationReport:
    month:              int       # 1-based: month within the contract year
    annual_commit:      float
    cumulative_actual:  float
    cumulative_expected: float    # monthly_commit * month

    @property
    def monthly_commit(self) -> float:
        return self.annual_commit / 12

    @property
    def utilisation_pct(self) -> float:
        return self.cumulative_actual / self.cumulative_expected * 100

    @property
    def run_rate_annual(self) -> float:
        """Annualised spend based on current month's cumulative actual."""
        return self.cumulative_actual / self.month * 12

    @property
    def projected_annual_shortfall(self) -> float:
        """Estimate shortfall if current run rate continues to year-end."""
        return max(0, self.annual_commit - self.run_rate_annual)

    @property
    def status(self) -> str:
        if self.utilisation_pct >= 95:
            return "on_track"
        elif self.utilisation_pct >= 80:
            return "at_risk"
        else:
            return "underutilising"

    def alert(self) -> str | None:
        if self.status == "underutilising":
            return (
                f"Month {self.month}: utilisation {self.utilisation_pct:.1f}% — "
                f"projected shortfall ${self.projected_annual_shortfall:,.0f}. "
                f"Review adoption pipeline and consider accelerating planned use case launches."
            )
        if self.status == "at_risk":
            return (
                f"Month {self.month}: utilisation {self.utilisation_pct:.1f}% — "
                f"borderline. Monitor closely; no action required yet."
            )
        return None

# Example: 6 months into a $600k/year commit, cumulative actual is $240k
report = CommitUtilisationReport(
    month=6,
    annual_commit=600_000,
    cumulative_actual=240_000,   # running $40k/month
    cumulative_expected=300_000, # should be $50k/month by month 6
)
print(report.status)    # → "at_risk"
print(report.alert())   # → warning message
